68	  it.todo("single moonstone (newcomer, first contract): 25 + 2.5 + 5 → rounded up");
69	
70	  // ---- Component blocks ----
71	  it.todo("2 runes → base premium 50 (no block)");
72	  it.todo("3 runes → base premium 60 (block applies)");
73	  it.todo("4 runes → base premium 100 (no block, requires exactly 3)");
74	  it.todo("7 runes → base premium 175 (one block + 4 extras → 60 + 100)");
75	  it.todo("2 runes + 1 moonstone → base premium 75 (different types, no block)");
