89	  it.todo("cursed sword + plain amulet (newcomer, first contract): cursed surcharge applies only to sword");
90	
91	  // ---- Rounding ----
92	  it.todo("premium calculation yielding fraction is rounded UP to whole G");
93	
94	  // ---- Claim: deductible and reimbursement ----
95	  it.todo("regular sword damage 500 → payout 400 (full minus 100 deductible)");
96	  it.todo("rune damage 200 → payout 100 (full minus 100 deductible)");
97	  it.todo("sword with enchantment 9, damage 1000 → payout 400 (50% then deductible)");
98	  it.todo("dragon-material sword enchantment 5, damage 800 → payout 700 (full minus deductible)");
