export type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
export type Step = { op: "quote"; items: Item[] };
export type Result = { premium: number };

const PROCESSING_FEE = 5;
const FIRST_INSURANCE_RATE = 0.1;

const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
};

const basePremiumFor = (item: Item): number => BASE_PREMIUM_BY_TYPE[item.type] ?? 0;

const quotePremium = (items: Item[]): number => {
  const base = items.reduce((sum, item) => sum + basePremiumFor(item), 0);
  const firstInsuranceSurcharge = base * FIRST_INSURANCE_RATE;
  return Math.ceil(base + firstInsuranceSurcharge + PROCESSING_FEE);
};
